(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn6"],{"01dd":function(n,t,a){"use strict";a.r(t);var r=function(){var n=this,t=n.$createElement,r=n._self._c||t;return r("markdown",{attrs:{source:a("ea14")}})},e=[],l=a("2877"),i={},o=Object(l["a"])(i,r,e,!1,null,null,null);o.options.__file="go.vue";t["default"]=o.exports},ea14:function(n,t){n.exports='## Go学习总结\n\n### 安装\n到golang官网下载，安装。\n```\nhttps://studygolang.com/dl\n```\n\n```s\n # 安装terminal插件后，按住shift+command+t即可快速打开当前文件夹的终端\n 按住shift+command+t即可快速打开当前文件夹的终端\n # 执行\n go run <要执行的文件>\n```\n\n### 变量定义\n```go\npackage main\n\nimport "fmt"\n\n/*\n＊ 在函数外边必须用va\br定义变量，用:=定义变量会报错。\n＊ 在函数外定义的变量不是全局变量，它在这个包内有效。\nvar aa = 3\nvar ss = "kkk"\n// bb := true  //会报错\n*/\nvar (\n  aa = 3\n  ss = "kkk"\n  bb = true\n)\n\nfunc variableZeroValue() {\n  var a int\n  var s string\n  fmt.Printf("%d %q\\n", a, s)\n  fmt.Println("-----------------")\n}\n\nfunc variableInitialValue() {\n  var a, b int = 3, 4\n  var s string = "abc"\n  fmt.Println(a, b, s)\n  fmt.Println("-----------------")\n}\n\nfunc variableTypeDeduction() {\n  var a, b, c, s = 3, 4, true, "def"\n  fmt.Println(a, b, c, s)\n  fmt.Println("-----------------")\n}\n\nfunc variableShorter() {\n  // 定义变量可以用:=,尽量少使用var来定义变量\n  a, b, c, s := 3, 4, true, "def"\n  fmt.Println(a, b, c, s)\n  fmt.Println("-----------------")\n}\n\nfunc main() {\n  fmt.Println("Hello World")\n  variableZeroValue()\n  variableInitialValue()\n  variableTypeDeduction()\n  variableShorter()\n  fmt.Println(aa,ss,bb)\n}\n\n/*\n输出:\nHello World\n0 ""\n-----------------\n3 4 abc\n-----------------\n3 4 true def\n-----------------\n3 4 true def\n-----------------\n3 kkk true\n*/\n```\n\b小结\n```\n使用var关键字\n  var a,b,c bool\n  var s1,s2 string = "hello", "world"\n  可放在函数内，或者直接放在包内\n  使用var()集中定义变量\n让编译器自动决定类型\n  var a,b,i,s1,s2 = true,false,3,"hello","world"  \n使用:=定义变量\n  a,b,i,s1,s2 := true,false,3,"hello","world"  \n  只能在函数内使用\n```\n\n### 内置变量类型\n\ngo的内置变量类型\n```\nbool, string;\n(u)int, (u)int8, (u)int16, (u)int32, (u)int64, uintptr;\nbyte, rune\nfloat32, float64, complex64, complex128.\n\n其中(u)int的位数由操作系统决定；\nuintptr是指针；\nbyte和rune是int的别名，byte是8位rune是32位；\ncomplex64的实部和虚部都是float32，complex128的实部和虚部都是float64。\n```\n ```go\n package main\n\nimport (\n\t"fmt"\n\t"math"\n\t"math/cmplx"\n)\n\nfunc euler() {\n  // 复数\n  c := 3 + 4i\n  fmt.Println(cmplx.Abs(c))\n  //最美欧拉公式\n  fmt.Println(cmplx.Pow(math.E, 1i*math.Pi) + 1)\n  fmt.Printf("%.3f", cmplx.Exp(1i*math.Pi) + 1)\n}\n\nfunc main() {\n  euler() \n}\n/*\n输出:\n5\n(0+1.2246467991473515e-16i)\n(0.000+0.000i)\n */\n ```\n 强制类型转换\n ```go\nfunc triangle() {\n\tvar a, b int = 3, 4\n\tvar c int\n\tc = int(math.Sqrt(float64(a*a + b*b)))\n\tfmt.Println(c)\n}\n// 5\n ```'}}]);